//! Per-subagent invocation signatures — making the provisioned identity
//! enforceable.
//!
//! Every spawned subagent gets its own DID recorded in the fleet ledger and a
//! matching secret in a 0600 keyfile under [`store::agent_key_path`] (handed to
//! the node by *path*, never by value). The node signs its invocations with
//! that keyfile; a verifier loads the subagent's DID from the ledger and checks
//! the signature against it. Because the secret never leaves the keyfile and
//! the public DID is the audit anchor, a forged or stolen-id message that
//! wasn't signed by the real keyfile fails to verify.
//!
//! The scheme is P-256 ECDSA, matching `a0n-auth`'s `did:key` (multicodec
//! 0x1200), so a signature verifies against the exact DID string stored in the
//! ledger via [`a0n_auth::ucan::verifying_key_from_did`]. Signatures are the
//! fixed-size (r || s) form, identical to what a0n-auth's UCAN verify accepts.

use p256::ecdsa::signature::{Signer, Verifier};
use p256::ecdsa::{Signature, SigningKey, VerifyingKey};

use a0n_auth::ucan::verifying_key_from_did;

use crate::store;

/// Sign `msg` with a subagent secret-key hex (the contents of its 0600
/// keyfile). Returns the fixed-size (r || s, 64-byte) ECDSA signature.
pub fn sign_with_secret_hex(secret_hex: &str, msg: &[u8]) -> Result<Vec<u8>, String> {
    let bytes = hex::decode(secret_hex.trim()).map_err(|e| format!("bad secret hex: {e}"))?;
    let signing = SigningKey::from_slice(&bytes).map_err(|e| format!("bad secret key: {e}"))?;
    let sig: Signature = signing.sign(msg);
    Ok(sig.to_bytes().to_vec())
}

/// Sign `msg` with the subagent `id`'s 0600 keyfile (`store::agent_key_path`).
/// This is what the spawned node does to authenticate its invocations.
pub fn sign_with_keyfile(id: &str, msg: &[u8]) -> Result<Vec<u8>, String> {
    let path = store::agent_key_path(id);
    let secret_hex = std::fs::read_to_string(&path)
        .map_err(|e| format!("read agent keyfile {}: {e}", path.display()))?;
    sign_with_secret_hex(&secret_hex, msg)
}

/// Verify `sig` over `msg` against an explicit DID. Returns `false` for any
/// malformed input, an unknown DID, or a signature that does not match — never
/// panics, never errors: a verifier just wants a yes/no.
pub fn verify_with_did(did: &str, msg: &[u8], sig: &[u8]) -> bool {
    let Ok(vk): Result<VerifyingKey, _> = verifying_key_from_did(did) else {
        return false;
    };
    let Ok(signature) = Signature::from_slice(sig) else {
        return false;
    };
    vk.verify(msg, &signature).is_ok()
}

/// Verify `sig` over `msg` against the DID the fleet ledger records for subagent
/// `id`. This is the enforcement point: only a message signed by the keyfile
/// that pairs with the ledger's provisioned DID for `id` verifies. Returns
/// `false` if there is no such subagent.
pub fn verify_subagent_signature(id: &str, msg: &[u8], sig: &[u8]) -> bool {
    let fleet = store::load_fleet();
    let Some(agent) = fleet.find(id) else {
        return false;
    };
    verify_with_did(&agent.did, msg, sig)
}

#[cfg(test)]
mod tests {
    use super::*;
    use crate::budget::Caste;
    use crate::ledger::{new_subagent, Fleet};
    use crate::store::ENV_GUARD;

    #[test]
    fn keyfile_signature_verifies_against_ledger_did() {
        let _env = ENV_GUARD.lock().unwrap();
        let dir =
            std::env::temp_dir().join(format!("monster-swarm-signtest-{}", std::process::id()));
        let _ = std::fs::remove_dir_all(&dir);
        std::fs::create_dir_all(&dir).unwrap();
        std::env::set_var("MONSTER_GUARD_HOME", &dir);

        // Provision a subagent exactly as `ops::spawn` does: a fresh keypair,
        // its DID in the ledger, its secret in the 0600 keyfile.
        let kp = a0n_auth::Keypair::generate();
        let did = kp.did().to_string();
        let id = "siggy";
        store::write_agent_key(id, &kp.secret_hex()).expect("write keyfile");

        let mut fleet = Fleet::default();
        fleet.add(new_subagent(
            id.to_string(),
            format!("agent-{id}"),
            did.clone(),
            "did:key:zSpawner".into(),
            Caste::Scout,
            vec!["net".into()],
            "fat-station".into(),
            vec![],
            60,
            Some(1),
            None,
            false,
            None,
            1,
        ));
        store::save_fleet(&fleet).expect("save fleet");

        let msg = b"invoke: decode-next pos=0 token=785";

        // The keyfile owner can sign, and the ledger DID verifies it.
        let sig = sign_with_keyfile(id, msg).expect("sign with keyfile");
        assert!(
            verify_subagent_signature(id, msg, &sig),
            "a keyfile signature must verify against the ledger DID"
        );

        // Tampering with the message breaks verification.
        assert!(
            !verify_subagent_signature(id, b"invoke: decode-next pos=1 token=785", &sig),
            "a signature must not verify over a different message"
        );

        // A signature from a DIFFERENT key (an impostor) fails against the DID.
        let impostor = a0n_auth::Keypair::generate();
        let forged = sign_with_secret_hex(&impostor.secret_hex(), msg).expect("impostor sign");
        assert!(
            !verify_subagent_signature(id, msg, &forged),
            "a signature from a non-provisioned key must be rejected"
        );

        // An unknown subagent id never verifies.
        assert!(!verify_subagent_signature("nobody", msg, &sig));

        // Garbage signature bytes are rejected without panicking.
        assert!(!verify_subagent_signature(id, msg, &[0u8; 8]));
        assert!(!verify_with_did(&did, msg, &[]));
        assert!(!verify_with_did("did:key:znotarealkey", msg, &sig));

        store::remove_agent_key(id);
        std::env::remove_var("MONSTER_GUARD_HOME");
        let _ = std::fs::remove_dir_all(&dir);
    }
}
